external_knowledge:
- "harbingers of bidding wars" refers to notifications indicating bids have been placed;
- "rank among a user’s biddings" means the notifications are ranked by the bid time for each user in descending order;
- "warriors" are buyers who have placed bids;
- "battle cries" metaphorically represent the bid amounts;
- "time of the shout" represents the time when the bid was made.

sql:
SELECT name
FROM auction_items
WHERE item_status = 'active' AND seller = 'Paruri';

SELECT item_id, code, name, info
FROM auction_items
WHERE item_status = 'active';

SELECT COUNT(DISTINCT t.seller_id) AS NumberOfUniqueSellers
FROM transactions t
WHERE t.status = 'completed';

external_knowledge:
- "sailing the high seas of luxury" metaphorically refers to items that are very expensive and exclusive;
- "starting bid exceeding a thousand" means the auction starting price is more than 1000 units;
- "line up in their grand parade from the most costly to the least" implies sorting the items by their starting bid in descending order.

sql:
SELECT COUNT(*) as items_under_threshold
FROM auction_items
WHERE CAST(current_bid AS REAL) < 50;
